	public static final class ProjectionPushdownRule extends AbstractRule {
		public ProjectionPushdownRule() {
			super("projection-pushdown", RuleKind.TRANSFORMATION, 40);
		}

		@Override
		public boolean matches(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return expression.logical()
					&& expression.tupleExpr()instanceof Projection projection
					&& projection.getArg() instanceof Join;
		}

		@Override
		public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			Projection projection = (Projection) expression.tupleExpr();
			Join join = (Join) projection.getArg();
			Set<String> projected = identityProjectionNames(projection);
			if (projected == null) {
				return List.of();
			}
			BindingUniverse universe = context.universe();
			BindingMask leftNames = CascadesRewriteSupport.mask(universe, join.getLeftArg().getBindingNames());
			BindingMask rightNames = CascadesRewriteSupport.mask(universe, join.getRightArg().getBindingNames());
			BindingMask projectedNames = CascadesRewriteSupport.mask(universe, projected);
			BindingMask shared = leftNames.intersect(rightNames);
			BindingMask leftNeededMask = projectedNames.intersect(leftNames).union(shared);
			BindingMask rightNeededMask = projectedNames.intersect(rightNames).union(shared);
			if (leftNeededMask.equals(leftNames) && rightNeededMask.equals(rightNames)) {
				return List.of();
			}
			Set<String> leftNeeded = universe.names(leftNeededMask);
			Set<String> rightNeeded = universe.names(rightNeededMask);

			Projection alternative = projection.clone();
			alternative.setArg(new Join(projectJoinInput(join.getLeftArg(), leftNeeded),
					projectJoinInput(join.getRightArg(), rightNeeded)));
			RuleProof proof = proof(semanticScope(goal), Set.of("projectedVarsVisible", "joinSharedVarsRetained"),
					"projection is retained while child inputs are pruned to projected and shared join variables");
			return List.of(RuleApplication.transformation(expression.groupId(), alternative, proof));
		}
	}

